var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"후우. 아슬아슬했네.","JPN":"ふぅ、ギリギリだったわね。","ENG":"Whew, that was close.","TWN":"呼，好險。"},"stage":{"bg":"X_MAS_HOUSE","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_LAUGH"}}}},{"id":"L4_1","type":"dialog","speaker":"SYLVIA_XMAS_NULL_NULL","text":{"KOREA":"펴...... 평생 뛸 것 오늘 다 뛴 기분이야......","JPN":"い……一生分動いた気がする。","ENG":"I... I don't think I want to run ever again...","TWN":"感……感覺我這一輩子要跑的都跑完了……"},"stage":{"bg":"X_MAS_HOUSE","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_LAUGH"}}}},{"id":"L5_1","type":"dialog","speaker":"SYLVIA_XMAS_NULL_NULL","text":{"KOREA":"그래서, 생존자는 우리 셋뿐이야?","JPN":"それで、生存者は私たち三人だけ？","ENG":"So, are the three of us the only survivors?","TWN":"所以，現在倖存者就只剩我們三個人了是嗎？"},"stage":{"bg":"X_MAS_HOUSE","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_LAUGH"}}}},{"id":"L7_1","type":"dialog","speaker":"GREATSWORD_XMAS_NULL_NULL","text":{"KOREA":"지금으로선 그래. 다른 애들은 전부 저기서 우릴 찾고 있잖아?","JPN":"現状はそうね。他の子たちはみんな、あそこで私たちを探してるみたいだし。","ENG":"For now, yes. The others are over there, looking for us.","TWN":"目前來說是的。其他人都在找我們呢。"},"stage":{"bg":"X_MAS_HOUSE","slots":{"L":null,"C":{"char_id":"GREATSWORD_XMAS_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SYLVIA_XMAS_NULL_NULL","text":{"KOREA":"카운터들이 전부 손도 못 쓰고 당하다니...... 진짜 유령 아냐?","JPN":"カウンターたちが抵抗もできずにやられるなんて……本当に幽霊なんじゃない？","ENG":"These Counters went down without even knowing what hit them. What if it really is a ghost?","TWN":"制裁者居然這麼輕易就被控制了……難道真的是鬼幹的好事？"},"stage":{"bg":"X_MAS_HOUSE","slots":{"L":null,"C":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SYLVIA_XMAS_NULL_NULL","text":{"KOREA":"이럴 줄 알았으면 카일 녀석 뒤통수를 리프노드로 후려쳐서라도 돌아가는 건데......","JPN":"こうなるとわかってたら、カイルのやつの後頭部をリーフノードで殴り飛ばして、帰れば良かった。","ENG":"I wish I knew better. I would have hit Kyle on the back of his head with Leaf Node if I had to drag him out of here.","TWN":"早知如此，哪怕用節點打死凱爾那個傢伙，也應該回去的……"},"stage":{"bg":"X_MAS_HOUSE","slots":{"L":null,"C":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SYLVIA_XMAS_NULL_NULL","text":{"KOREA":"아냐. 탄도 미사일을 발사시키겠다고 협박했으면......","JPN":"いや、弾道ミサイルを発射するって脅しておけば……","ENG":"Or I could just have threatened to launch a ballistic missile...","TWN":"不，應該威脅他說要發射彈道導彈的……"},"stage":{"bg":"X_MAS_HOUSE","slots":{"L":null,"C":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"GREATSWORD_XMAS_NULL_NULL","text":{"KOREA":"방식이 조금 과격한 아이였구나. 무서워라.","JPN":"やり方が少し過激なのね。怖いわ。","ENG":"I didn't know you were so aggressive. Scary!","TWN":"妳這孩子有點過激啊，我好害怕。"},"stage":{"bg":"X_MAS_HOUSE","slots":{"L":null,"C":{"char_id":"GREATSWORD_XMAS_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"진정하세요, 실비아 씨.","JPN":"落ち着いてください、シルビアさん。","ENG":"Calm down, Sylvia.","TWN":"冷靜點，希爾維亞。"},"stage":{"bg":"X_MAS_HOUSE","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"유령 얘기로 혼란스러우신 건 알겠지만, 이럴 때일수록 침착해야 돼요.","JPN":"幽霊の話で混乱しているのはわかりますが、こういう時ほど冷静になる必要があります。","ENG":"I understand that this ghost story is confusing, but we shouldn't let it get to us, especially at a time like this.","TWN":"我知道鬼不鬼的讓妳感到很混亂，但越是這種時候就越要冷靜。"},"stage":{"bg":"X_MAS_HOUSE","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"SYLVIA_XMAS_NULL_NULL","text":{"KOREA":"그, 그래. 무서운 건 아니고 정신이 없는 거지......","JPN":"わかったわよ。でも、怖いんじゃなくてちょっと落ち着かないだけ……","ENG":"O-okay. I'm not scared. I'm just not clear-headed...","TWN":"好，好。我不是怕，我只是亂……"},"stage":{"bg":"X_MAS_HOUSE","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"고립된 지역이라는 조건은 그대로잖아요. 생존자가 우리 셋이면 그 중 한 명은 범인이겠죠.","JPN":"孤立した地域という条件は変わっていません。生存者が私たち3人ならその中の誰かが犯人だということです。","ENG":"We're still stuck in this area. Since only the three of us are left, one of us has to be the culprit.","TWN":"這裡仍然是孤立的地區，就是說兇手就在我們三個倖存者當中。"},"stage":{"bg":"X_MAS_HOUSE","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"SYLVIA_XMAS_NULL_NULL","text":{"KOREA":"그건......","JPN":"それは……","ENG":"Well...","TWN":"這個……"},"stage":{"bg":"X_MAS_HOUSE","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"SYLVIA_XMAS_NULL_NULL","text":{"KOREA":"주시윤 녀석한테 붙어 있던 유령이 전자기 펄스에 떨어져 나갔을지도 모르잖아.","JPN":"アキヤマ・シリュウについてた幽霊が、電磁パルスでどっかに飛ばされた可能性だってあるでしょ。","ENG":"Maybe it really was a ghost and it was driven out of Shiyoon by my EMP.","TWN":"說不定在周時雲身上的鬼，因為電磁脈衝分離了呢？"},"stage":{"bg":"X_MAS_HOUSE","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"그 점은 저도 사장님과 같은 생각이에요. 유령 같은 비과학적인 현상은 있을 수 없어요.","JPN":"それは私も社長と同じ考えです。幽霊のような非科学的な現象はあり得ません。","ENG":"I have to agree with the Boss on that. Paranormal phenomena like ghosts don't exist.","TWN":"我和老闆的想法一樣，這世上根本就不存在像鬼這樣的非科學現象。"},"stage":{"bg":"X_MAS_HOUSE","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_PRIDE"}}}},{"id":"L21_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"아무리 말이 안 되는 것 같아도 차근차근 의심해가다 보면 해답에 다다를 수 있어요.","JPN":"いくらあり得ないように思えても、一つずつ疑っていけば答えに辿り着けます。","ENG":"No matter how mysterious this looks, we can solve it if we apply ourselves.","TWN":"即使多麼荒唐，只要仔細斟酌一番，就可以找到答案。"},"stage":{"bg":"X_MAS_HOUSE","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"SYLVIA_XMAS_NULL_NULL","text":{"KOREA":"......좋아, 네 말대로 그럼 여기 있는 셋 중에 한 명이 범인이라고 쳐.","JPN":"……じゃあ、アンタの言うとおり、この三人のうち一人が犯人だとして。","ENG":"Okay, then let's say one of us is the perpetrator.","TWN":"……好，就像妳說的，兇手就在我們三個人當中。"},"stage":{"bg":"X_MAS_HOUSE","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"SYLVIA_XMAS_NULL_NULL","text":{"KOREA":"그럼 제일 의심 가는 사람은 너 아냐? 남들 뒤통수 치는 게 네 특기잖아?","JPN":"一番怪しいのは、アンタじゃない？　人を裏切るのがアンタの特技だし。","ENG":"Then aren't you the most likely suspect? Since backstabbing is your expertise?","TWN":"那麼最可疑的不就是妳？妳的特長不就是背叛別人嗎？"},"stage":{"bg":"X_MAS_HOUSE","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};